import { createContext, useContext, useEffect, useState, useCallback, ReactNode } from 'react';
import { createPortal } from 'react-dom';

type Toast = { id: number; message: string; ttl: number };

const listeners = new Set<(toasts: Toast[]) => void>();
let toasts: Toast[] = [];
let nextId = 0;

export function toast(message: string, ttl = 3000) {
  const t: Toast = { id: nextId++, message, ttl };
  toasts = [...toasts, t];
  listeners.forEach((fn) => fn(toasts));
  setTimeout(() => {
    toasts = toasts.filter((x) => x.id !== t.id);
    listeners.forEach((fn) => fn(toasts));
  }, ttl);
}

export function ToastViewport() {
  const [items, setItems] = useState<Toast[]>(toasts);
  useEffect(() => {
    const fn = (next: Toast[]) => setItems(next);
    listeners.add(fn);
    return () => { listeners.delete(fn); };
  });
  return createPortal(
    <div className="fixed top-4 right-4 space-y-2">
      {items.map((t) => <div key={t.id} className="bg-slate-800 text-white p-3 rounded">{t.message}</div>)}
    </div>,
    document.body
  );
}

