import { useEffect, useState, useSyncExternalStore } from 'react';
import { createPortal } from 'react-dom';

type Toast = { id: number; message: string; ttl: number };

const store = (() => {
  let toasts: Toast[] = [];
  let nextId = 0;
  const listeners = new Set<() => void>();
  const timers = new Map<number, ReturnType<typeof setTimeout>>();
  const api = {
    subscribe(fn: () => void) { listeners.add(fn); return () => listeners.delete(fn); },
    getSnapshot() { return toasts; },
    getServerSnapshot() { return [] as Toast[]; },
    push(message: string, ttl = 3000) {
      const t: Toast = { id: nextId++, message, ttl };
      toasts = [...toasts, t];
      listeners.forEach((fn) => fn());
      timers.set(t.id, setTimeout(() => api.dismiss(t.id), ttl));
    },
    dismiss(id: number) {
      const timer = timers.get(id);
      if (timer) { clearTimeout(timer); timers.delete(id); }
      toasts = toasts.filter((x) => x.id !== id);
      listeners.forEach((fn) => fn());
    },
    reset() {
      timers.forEach(clearTimeout); timers.clear();
      toasts = []; nextId = 0;
      listeners.forEach((fn) => fn());
    },
  };
  return api;
})();

export const toast = store.push;
export const __resetToastsForTests = store.reset;

export function ToastViewport() {
  const items = useSyncExternalStore(store.subscribe, store.getSnapshot, store.getServerSnapshot);
  const [mounted, setMounted] = useState(false);
  useEffect(() => { setMounted(true); }, []);
  if (!mounted) return null;
  return createPortal(
    <div className="fixed top-4 right-4 space-y-2">
      {items.map((t) => (
        <div key={t.id} className="bg-slate-800 text-white p-3 rounded">{t.message}</div>
      ))}
    </div>,
    document.body
  );
}

