import { useSyncExternalStore, useCallback, Dispatch, SetStateAction } from 'react';

function safeParse<T>(raw: string | null, fallback: T): T {
  if (raw === null) return fallback;
  try { return JSON.parse(raw) as T; } catch { return fallback; }
}

export function useLocalStorage<T>(key: string, initial: T): [T, Dispatch<SetStateAction<T>>] {
  const subscribe = useCallback((cb: () => void) => {
    const handler = (e: StorageEvent) => { if (e.key === key) cb(); };
    window.addEventListener('storage', handler);
    return () => window.removeEventListener('storage', handler);
  }, [key]);

  const getSnapshot = useCallback(() => safeParse<T>(localStorage.getItem(key), initial), [key, initial]);
  const getServerSnapshot = useCallback(() => initial, [initial]);

  const value = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);

  const setValue: Dispatch<SetStateAction<T>> = useCallback((next) => {
    const resolved = typeof next === 'function' ? (next as (p: T) => T)(value) : next;
    localStorage.setItem(key, JSON.stringify(resolved));
    // Manually dispatch event so OTHER hooks in this tab pick it up too.
    window.dispatchEvent(new StorageEvent('storage', { key }));
  }, [key, value]);

  return [value, setValue];
}

