import { useState, useRef, useEffect, useId, KeyboardEvent } from 'react';

type Item = { id: string; label: string; onSelect: () => void };

export function DropdownMenu({ items, trigger }: { items: Item[]; trigger: string }) {
  const [open, setOpen] = useState(false);
  const [activeIdx, setActiveIdx] = useState(0);
  const wrapRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const itemRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const menuId = useId();

  useEffect(() => {
    if (!open) return;
    itemRefs.current[activeIdx]?.focus();
  }, [open, activeIdx]);

  useEffect(() => {
    const onClick = (e: MouseEvent) => {
      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener('click', onClick);
    return () => document.removeEventListener('click', onClick);
  }, []);

  function onKey(e: KeyboardEvent) {
    if (e.key === 'Escape') { setOpen(false); triggerRef.current?.focus(); }
    else if (e.key === 'ArrowDown') { e.preventDefault(); setActiveIdx((i) => (i + 1) % items.length); }
    else if (e.key === 'ArrowUp')   { e.preventDefault(); setActiveIdx((i) => (i - 1 + items.length) % items.length); }
    else if (e.key === 'Home')      { e.preventDefault(); setActiveIdx(0); }
    else if (e.key === 'End')       { e.preventDefault(); setActiveIdx(items.length - 1); }
    else if (e.key === 'Tab')       { setOpen(false); }
  }

  return (
    <div ref={wrapRef} className="relative">
      <button
        ref={triggerRef}
        type="button"
        aria-haspopup="menu"
        aria-expanded={open}
        aria-controls={menuId}
        onClick={() => setOpen((o) => !o)}
      >
        {trigger}
      </button>
      {open && (
        <div
          id={menuId}
          role="menu"
          aria-orientation="vertical"
          className="absolute mt-2 bg-white shadow rounded"
          onKeyDown={onKey}
        >
          {items.map((it, i) => (
            <button
              key={it.id}
              ref={(el) => { itemRefs.current[i] = el; }}
              type="button"
              role="menuitem"
              tabIndex={i === activeIdx ? 0 : -1}
              className="block w-full text-left px-3 py-2 hover:bg-slate-100 focus:bg-slate-100 focus:outline-none"
              onClick={() => { it.onSelect(); setOpen(false); triggerRef.current?.focus(); }}
            >
              {it.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

