import { createContext, useContext, useEffect, useMemo, useState, useCallback, useSyncExternalStore, ReactNode } from 'react';

type Theme = 'light' | 'dark';
type Pref = Theme | 'system';

const ThemeStateContext = createContext<Theme | null>(null);
const ThemePrefContext  = createContext<{ pref: Pref; setPref: (p: Pref) => void } | null>(null);

function subscribeMQ(cb: () => void) {
  const mq = window.matchMedia('(prefers-color-scheme: dark)');
  mq.addEventListener('change', cb);
  return () => mq.removeEventListener('change', cb);
}
function getSystemTheme(): Theme {
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}
function getServerTheme(): Theme { return 'light'; }

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [pref, setPrefState] = useState<Pref>(() =>
    (typeof window !== 'undefined' && (localStorage.getItem('theme') as Pref)) || 'system'
  );
  const system = useSyncExternalStore(subscribeMQ, getSystemTheme, getServerTheme);
  const theme: Theme = pref === 'system' ? system : pref;

  const setPref = useCallback((p: Pref) => {
    setPrefState(p);
    localStorage.setItem('theme', p);
  }, []);

  useEffect(() => {
    document.documentElement.dataset.theme = theme;
  }, [theme]);

  const prefValue = useMemo(() => ({ pref, setPref }), [pref, setPref]);

  return (
    <ThemeStateContext.Provider value={theme}>
      <ThemePrefContext.Provider value={prefValue}>
        {children}
      </ThemePrefContext.Provider>
    </ThemeStateContext.Provider>
  );
}

export function useTheme(): Theme {
  const ctx = useContext(ThemeStateContext);
  if (ctx === null) throw new Error('useTheme must be used inside <ThemeProvider>');
  return ctx;
}
export function useThemePref() {
  const ctx = useContext(ThemePrefContext);
  if (!ctx) throw new Error('useThemePref must be used inside <ThemeProvider>');
  return ctx;
