export function VirtualList({
  items,
  itemHeight = 40,
  height = 480,
  scrollToIndex,
}: {
  items: { id: string; text: string }[];
  itemHeight?: number;
  height?: number;
  scrollToIndex?: number;
}) {
  const ref = useRef<HTMLDivElement>(null);
  const [scrollTop, setScrollTop] = useState(0);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const onScroll = () => setScrollTop(el.scrollTop);
    el.addEventListener('scroll', onScroll);
    return () => el.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    if (scrollToIndex == null || !ref.current) return;
    ref.current.scrollTo({ top: scrollToIndex * itemHeight, behavior: 'smooth' });
  }, [scrollToIndex, itemHeight]);

  const start = Math.floor(scrollTop / itemHeight);
  const visibleCount = Math.ceil(height / itemHeight) + 2;
  const end = Math.min(items.length, start + visibleCount);
  const offset = start * itemHeight;

  return (
    <div ref={ref} style={{ height, overflowY: 'auto' }}>
      <div style={{ height: items.length * itemHeight, position: 'relative' }}>
        <div style={{ transform: `translateY(${offset}px)` }}>
