import { memo, useEffect, useRef, useState, useCallback } from 'react';

export const VirtualList = memo(function VirtualList({
  items,
  itemHeight = 40,
  height = 480,
  scrollToIndex,
}: {
  items: { id: string; text: string }[];
  itemHeight?: number;
  height?: number;
  scrollToIndex?: number;
}) {
  const ref = useRef<HTMLDivElement>(null);
  const [scrollTop, setScrollTop] = useState(0);
  const rafRef = useRef<number | null>(null);
  const lastIndexRef = useRef<number | undefined>(undefined);

  const onScroll = useCallback(() => {
    if (rafRef.current != null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      if (ref.current) setScrollTop(ref.current.scrollTop);
    });
  }, []);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    el.addEventListener('scroll', onScroll, { passive: true });
    return () => {
      el.removeEventListener('scroll', onScroll);
      if (rafRef.current != null) cancelAnimationFrame(rafRef.current);
    };
  }, [onScroll]);

  useEffect(() => {
    if (scrollToIndex == null || !ref.current) return;
    if (lastIndexRef.current === scrollToIndex) return; // dedupe
    lastIndexRef.current = scrollToIndex;
    const target = scrollToIndex * itemHeight;
    const distance = Math.abs(target - ref.current.scrollTop);
    const behavior: ScrollBehavior = distance > height * 5 ? 'auto' : 'smooth';
    ref.current.scrollTo({ top: target, behavior });
  }, [scrollToIndex, itemHeight, height]);

  const start = Math.floor(scrollTop / itemHeight);
  const visibleCount = Math.ceil(height / itemHeight) + 2;
  const end = Math.min(items.length, start + visibleCount);
  const offset = start * itemHeight;

