import { useEffect, useRef, ReactNode, useId } from 'react';
import { createPortal } from 'react-dom';

// Ref-counted body scroll lock that survives stacked modals and iOS Safari.
const lockState = { count: 0, savedScrollY: 0, savedStyle: '' };
function lockBody() {
  if (lockState.count++ === 0) {
    lockState.savedScrollY = window.scrollY;
    lockState.savedStyle = document.body.style.cssText;
    document.body.style.position = 'fixed';
    document.body.style.top = `-${lockState.savedScrollY}px`;
    document.body.style.left = '0';
    document.body.style.right = '0';
  }
}
function unlockBody() {
  if (--lockState.count === 0) {
    document.body.style.cssText = lockState.savedStyle;
    window.scrollTo(0, lockState.savedScrollY);
  }
}

export function Modal({ open, onClose, children, titleId }: { open: boolean; onClose: () => void; children: ReactNode; titleId?: string }) {
  const dialogRef = useRef<HTMLDivElement>(null);
  const lastActiveRef = useRef<HTMLElement | null>(null);
  const fallbackTitleId = useId();
  const labelId = titleId ?? fallbackTitleId;

  useEffect(() => {
    if (!open) return;
    lockBody();
    lastActiveRef.current = document.activeElement as HTMLElement;
    const first = dialogRef.current?.querySelector<HTMLElement>('button, [href], input, textarea, select, [tabindex]:not([tabindex="-1"])');
    first?.focus();

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
      if (e.key === 'Tab' && dialogRef.current) {
        const focusables = dialogRef.current.querySelectorAll<HTMLElement>('button, [href], input, textarea, select, [tabindex]:not([tabindex="-1"])');
        if (!focusables.length) return;
        const firstEl = focusables[0]; const lastEl = focusables[focusables.length - 1];
        if (e.shiftKey && document.activeElement === firstEl) { e.preventDefault(); lastEl.focus(); }
        else if (!e.shiftKey && document.activeElement === lastEl) { e.preventDefault(); firstEl.focus(); }
      }
    };
    window.addEventListener('keydown', onKey);
    return () => {
      window.removeEventListener('keydown', onKey);
      unlockBody();
      lastActiveRef.current?.focus();
    };
  }, [open, onClose]);

  if (!open) return null;

  return createPortal(
    <div
      className="fixed inset-0 bg-black/50 flex items-center justify-center"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby={labelId}
        className="bg-white rounded-lg p-6"
      >
        {children}
      </div>
    </div>,
    document.body
  );
}

