class HttpError extends Error {
  constructor(public status: number, message: string) { super(message); this.name = 'HttpError'; }
}

type State<T> =
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: Error };

export function useFetch<S extends ZodType>(url: string, schema: S): State<z.infer<S>> {
  type T = z.infer<S>;
  const [state, setState] = useState<State<T>>({ status: 'loading' });

  useEffect(() => {
    const ac = new AbortController();
    setState({ status: 'loading' });
    (async () => {
      try {
        const r = await fetch(url, { signal: ac.signal });
        if (!r.ok) throw new HttpError(r.status, r.statusText);
        const raw: unknown = await r.json();
        const parsed = schema.parse(raw); // throws ZodError on shape mismatch
        if (ac.signal.aborted) return;
        setState({ status: 'success', data: parsed });
      } catch (err) {
        if (!(err instanceof Error)) throw err;
        if (err.name === 'AbortError') return;
        if (ac.signal.aborted) return;
        setState({ status: 'error', error: err });
      }
    })();
    return () => ac.abort();
  }, [url, schema]);

  return state;
}

// Usage
const UserSchema = z.object({ id: z.string(), name: z.string(), email: z.string().email() });
export function UserCard({ id }: { id: string }) {
  const result = useFetch(`/api/users/${id}`, UserSchema);
  if (result.status === 'success') return <div>{result.data.name}</div>;
  if (result.status === 'error') return <div className="text-red-600">{result.error.message}</div>;
  return <div>Loading...</div>;
}

