import { useEffect, useRef, useState } from 'react';
import { z } from 'zod';

const EmailSchema = z.string().email();

type EmailStatus = { kind: 'idle' } | { kind: 'invalid' } | { kind: 'checking' } | { kind: 'valid' } | { kind: 'taken' } | { kind: 'unknown' };

export function SignupForm() {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<EmailStatus>({ kind: 'idle' });
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (!email) { setStatus({ kind: 'idle' }); return; }
    if (!EmailSchema.safeParse(email).success) { setStatus({ kind: 'invalid' }); return; }

    const ac = new AbortController();
    setStatus({ kind: 'checking' });
    const t = setTimeout(async () => {
      try {
        const url = `/api/check-email?${new URLSearchParams({ email })}`;
        const r = await fetch(url, { signal: ac.signal });
        if (ac.signal.aborted) return;
        if (!r.ok) { setStatus({ kind: 'unknown' }); return; }
        const { taken } = await r.json();
        setStatus(taken ? { kind: 'taken' } : { kind: 'valid' });
      } catch (err) {
        if ((err as Error).name === 'AbortError') return;
        setStatus({ kind: 'unknown' });
      }
    }, 300);
    return () => { clearTimeout(t); ac.abort(); };
  }, [email]);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (status.kind !== 'valid' || submitting) return;
    setSubmitting(true);
    try {
      await fetch('/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <form onSubmit={onSubmit}>
      <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} />
      {status.kind === 'checking' && <span>checking...</span>}
      {status.kind === 'invalid' && <span className="text-red-600">Invalid email</span>}
      {status.kind === 'taken' && <span className="text-red-600">Email already in use</span>}
      {status.kind === 'unknown' && <span className="text-amber-600">Couldn't verify - we'll re-check on submit</span>}
      <button type="submit" disabled={status.kind !== 'valid' || submitting}>
        {submitting ? 'Signing up...' : 'Sign up'}
      </button>
    </form>
  );
}

