import { useEffect, useState, useCallback, useRef } from 'react';

type Size = { width: number; height: number };

// Pooled singleton observer.
type Listener = (rect: DOMRectReadOnly) => void;
let pool: ResizeObserver | null = null;
const listeners = new Map<Element, Set<Listener>>();
function getPool() {
  if (typeof window === 'undefined') return null;
  if (!pool) {
    pool = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const subs = listeners.get(entry.target);
        if (!subs) continue;
        for (const fn of subs) fn(entry.contentRect);
      }
    });
  }
  return pool;
}

export function useResizeObserver<T extends Element>(): [(el: T | null) => void, Size] {
  const [size, setSize] = useState<Size>({ width: 0, height: 0 });
  const elRef = useRef<T | null>(null);
  const rafRef = useRef<number | null>(null);

  const setRef = useCallback((el: T | null) => {
    const p = getPool();
    if (!p) return;
    if (elRef.current) {
      const subs = listeners.get(elRef.current);
      subs?.delete(onResize);
      if (subs && subs.size === 0) { p.unobserve(elRef.current); listeners.delete(elRef.current); }
    }
    elRef.current = el;
    if (el) {
      if (!listeners.has(el)) { listeners.set(el, new Set()); p.observe(el); }
      listeners.get(el)!.add(onResize);
      const rect = el.getBoundingClientRect();
      setSize({ width: rect.width, height: rect.height });
    }
  }, []);

  const onResize: Listener = useCallback((rect) => {
    if (rafRef.current != null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      setSize((prev) => (prev.width === rect.width && prev.height === rect.height ? prev : { width: rect.width, height: rect.height }));
    });
  }, []);

  useEffect(() => () => {
    if (rafRef.current != null) cancelAnimationFrame(rafRef.current);
    if (elRef.current) {
      const subs = listeners.get(elRef.current);
      subs?.delete(onResize);
    }
  }, [onResize]);

  return [setRef, size];
}

