import { Component, ReactNode, ErrorInfo } from 'react';
import * as Sentry from '@sentry/react';

type FallbackRender = (props: { error: Error; reset: () => void }) => ReactNode;
type Props = { children: ReactNode; fallback?: ReactNode | FallbackRender; resetKey?: unknown };
type State = { hasError: boolean; error: Error | null };

export class ErrorBoundary extends Component<Props, State> {
  state: State = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    Sentry.captureException(error, {
      contexts: { react: { componentStack: info.componentStack ?? '(no stack)' } },
    });
  }

  componentDidUpdate(prev: Props) {
    if (this.state.hasError && prev.resetKey !== this.props.resetKey) {
      this.setState({ hasError: false, error: null });
    }
  }

  reset = () => this.setState({ hasError: false, error: null });

  render() {
    if (this.state.hasError && this.state.error) {
      const { fallback } = this.props;
      if (typeof fallback === 'function') return (fallback as FallbackRender)({ error: this.state.error, reset: this.reset });
      return fallback ?? <div>Something went wrong <button onClick={this.reset}>Try again</button></div>;
    }
    return this.props.children;
  }
}

// Global async-error capture, since boundaries don't catch these.
if (typeof window !== 'undefined') {
  window.addEventListener('unhandledrejection', (e) => Sentry.captureException(e.reason));
  window.addEventListener('error', (e) => Sentry.captureException(e.error));
}

// Layered usage:
export function App() {
  return (
    <ErrorBoundary>
      {/* root: catastrophic crashes */}
      <RouteBoundary />
    </ErrorBoundary>
  );
}
function RouteBoundary() {
  const pathname = typeof window !== 'undefined' ? window.location.pathname : '/';
  return (
    <ErrorBoundary resetKey={pathname}>
      {/* per-route: recoverable */}
      <Router />
    </ErrorBoundary>
  );
}

