import { useState, useRef, useEffect, useId, ReactNode } from 'react';
import { createPortal } from 'react-dom';

export function Tooltip({ content, children, delay = 300 }: { content: ReactNode; children: ReactNode; delay?: number }) {
  const [open, setOpen] = useState(false);
  const [coords, setCoords] = useState({ x: 0, y: 0 });
  const [mounted, setMounted] = useState(false);
  const triggerRef = useRef<HTMLSpanElement>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const id = useId();

  useEffect(() => { setMounted(true); }, []);
  useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);

  const show = () => {
    if (timerRef.current) clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => {
      const r = triggerRef.current?.getBoundingClientRect();
      if (r) setCoords({ x: r.left + r.width / 2, y: r.top });
      setOpen(true);
    }, delay);
  };
  const hide = () => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setOpen(false);
  };

  return (
    <>
      <span
        ref={triggerRef}
        onMouseEnter={show}
        onMouseLeave={hide}
        onFocus={show}
        onBlur={hide}
        aria-describedby={open ? id : undefined}
        className="inline-block"
      >
        {children}
      </span>
      {mounted && open && createPortal(
        <span
          id={id}
          role="tooltip"
          style={{ position: 'fixed', left: coords.x, top: coords.y, transform: 'translate(-50%, calc(-100% - 4px))' }}
          className="px-2 py-1 bg-slate-900 text-white text-xs rounded pointer-events-none"
        >
          {content}
        </span>,
        document.body,
      )}
    </>
  );
}

