import { useEffect, useRef, useState, useCallback } from 'react';

type Item = { id: string; text: string };

export function ActivityFeed() {
  const [items, setItems] = useState<Item[]>([]);
  const [page, setPage] = useState(0);
  const [done, setDone] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const sentinelRef = useRef<HTMLDivElement>(null);
  const lastLoadedPage = useRef<number>(-1);

  useEffect(() => {
    if (page <= lastLoadedPage.current) return;
    const ac = new AbortController();
    setLoading(true);
    (async () => {
      try {
        const r = await fetch(`/api/activity?page=${page}`, { signal: ac.signal });
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        const res: { items: Item[]; hasMore: boolean } = await r.json();
        if (ac.signal.aborted) return;
        // ensure ordering: only apply if this is the next expected page
        if (page === lastLoadedPage.current + 1) {
          setItems((prev) => [...prev, ...res.items]);
          lastLoadedPage.current = page;
          if (!res.hasMore) setDone(true);
        }
      } catch (err) {
        if ((err as Error).name === 'AbortError') return;
        setError((err as Error).message);
      } finally {
        if (!ac.signal.aborted) setLoading(false);
      }
    })();
    return () => ac.abort();
  }, [page]);

  const onIntersect = useCallback((entries: IntersectionObserverEntry[]) => {
    if (loading || done) return;
    if (entries[0].isIntersecting) setPage((p) => p + 1);
  }, [loading, done]);

  useEffect(() => {
    const el = sentinelRef.current;
    if (done || !el) return;
    const io = new IntersectionObserver(onIntersect, { rootMargin: '200px' });
    io.observe(el);
    return () => io.disconnect();
  }, [done, onIntersect]);

  return (
    <div>
      {items.map((it) => <div key={it.id}>{it.text}</div>)}
      {error && (
        <div className="text-red-600">
          {error} <button onClick={() => { setError(null); setPage((p) => p); }}>Retry</button>
        </div>
      )}
      {!done && !error && <div ref={sentinelRef} style={{ height: 1 }} />}
    </div>
  );
}

