import { useState, useRef, useEffect, useId, KeyboardEvent } from 'react';

type Option = { value: string; label: string };

export function Select({
  options, value, onChange, name,
}: { options: Option[]; value: string; onChange: (v: string) => void; name?: string }) {
  const [open, setOpen] = useState(false);
  const [active, setActive] = useState(0);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const listId = useId();
  const selected = options.find((o) => o.value === value);

  useEffect(() => {
    if (!open) return;
    const onDoc = (e: MouseEvent) => {
      const t = e.target as Node;
      if (!triggerRef.current?.parentElement?.contains(t)) setOpen(false);
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [open]);

  function onKey(e: KeyboardEvent<HTMLDivElement>) {
    if (!open) {
      if (e.key === 'Enter' || e.key === ' ' || e.key === 'ArrowDown') { e.preventDefault(); setOpen(true); }
      return;
    }
    if (e.key === 'Escape' || e.key === 'Tab') { setOpen(false); triggerRef.current?.focus(); }
    else if (e.key === 'ArrowDown') { e.preventDefault(); setActive((i) => Math.min(options.length - 1, i + 1)); }
    else if (e.key === 'ArrowUp')   { e.preventDefault(); setActive((i) => Math.max(0, i - 1)); }
    else if (e.key === 'Home')      { e.preventDefault(); setActive(0); }
    else if (e.key === 'End')       { e.preventDefault(); setActive(options.length - 1); }
    else if (e.key === 'Enter')     { onChange(options[active].value); setOpen(false); triggerRef.current?.focus(); }
  }

  return (
    <div className="relative inline-block" onKeyDown={onKey}>
      <button
        ref={triggerRef}
        type="button"
        aria-haspopup="listbox"
        aria-expanded={open}
        aria-controls={listId}
        aria-activedescendant={open ? `${listId}-${active}` : undefined}
        onClick={() => setOpen((o) => !o)}
        className="border px-3 py-2 cursor-pointer"
      >
        {selected?.label ?? 'Select...'}
      </button>
      {name && <input type="hidden" name={name} value={value} />}
      {open && (
        <ul id={listId} role="listbox" className="absolute mt-1 border bg-white shadow w-full">
          {options.map((o, i) => (
            <li
              id={`${listId}-${i}`}
              key={o.value}
              role="option"
              aria-selected={value === o.value}
              className={`px-3 py-2 cursor-pointer ${i === active ? 'bg-slate-100' : ''}`}
              onMouseEnter={() => setActive(i)}
              onClick={() => { onChange(o.value); setOpen(false); triggerRef.current?.focus(); }}
            >
              {o.label}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

