import { useEffect, useState } from 'react';

type State = { status: 'connecting' | 'open' | 'closed'; messages: string[] };

export function useWebSocket(url: string): State {
  const [state, setState] = useState<State>({ status: 'connecting', messages: [] });

  useEffect(() => {
    const ws = new WebSocket(url);
    setState({ status: 'connecting', messages: [] });

    ws.onopen = () => setState((s) => ({ ...s, status: 'open' }));
    ws.onclose = () => setState((s) => ({ ...s, status: 'closed' }));
    ws.onmessage = (e) => setState((s) => ({ ...s, messages: [...s.messages, e.data] }));

    return () => ws.close();
  }, [url]);

  return state;
}

