import { useEffect, useState, useSyncExternalStore } from 'react';

type Status = 'connecting' | 'open' | 'closed';
type ConnectionState = { status: Status; lastMessage: unknown | null };

class ConnectionPool {
  private conns = new Map<string, ConnectionEntry>();
  acquire(url: string, onChange: () => void): () => void {
    let entry = this.conns.get(url);
    if (!entry) {
      entry = new ConnectionEntry(url, () => {
        // when entry has no subscribers, delay-close it
        if (entry!.subs.size === 0) {
          setTimeout(() => { if (entry!.subs.size === 0) { entry!.close(); this.conns.delete(url); } }, 1000);
        }
      });
      this.conns.set(url, entry);
    }
    entry.subs.add(onChange);
    return () => {
      entry!.subs.delete(onChange);
      entry!.onMaybeIdle();
    };
  }
  getState(url: string): ConnectionState {
    return this.conns.get(url)?.state ?? { status: 'connecting', lastMessage: null };
  }
}

class ConnectionEntry {
  state: ConnectionState = { status: 'connecting', lastMessage: null };
  subs = new Set<() => void>();
  private ws: WebSocket | null = null;
  private retries = 0;
  private mounted = true;
  constructor(private url: string, public onMaybeIdle: () => void) {
    this.open();
  }
  private open() {
    this.ws = new WebSocket(this.url);
    this.ws.addEventListener('open', () => { this.update({ ...this.state, status: 'open' }); this.retries = 0; });
    this.ws.addEventListener('close', () => {
      this.update({ ...this.state, status: 'closed' });
      if (this.mounted) {
        const wait = Math.min(1000 * 2 ** this.retries++, 30000);
        setTimeout(() => { if (this.mounted) this.open(); }, wait);
      }
    });
    this.ws.addEventListener('message', (e) => {
      try {
        this.update({ ...this.state, lastMessage: JSON.parse(e.data) });
      } catch {
        this.update({ ...this.state, lastMessage: e.data });
      }
    });
    this.ws.addEventListener('error', () => { /* will trigger close */ });
  }
  private update(next: ConnectionState) {
    this.state = next;
    this.subs.forEach((fn) => fn());
  }
  close() {
    this.mounted = false;
    this.ws?.close();
  }
}

const pool = new ConnectionPool();

export function useWebSocket(url: string): ConnectionState {
  const subscribe = (cb: () => void) => pool.acquire(url, cb);
  const getSnapshot = () => pool.getState(url);
  return useSyncExternalStore(subscribe, getSnapshot, () => ({ status: 'connecting' as const, lastMessage: null }));
}

