import { useState, useRef, useEffect } from 'react';

async function copyText(value: string): Promise<boolean> {
  // Prefer modern Clipboard API.
  if (typeof navigator !== 'undefined' && navigator.clipboard && window.isSecureContext) {
    try {
      await navigator.clipboard.writeText(value);
      return true;
    } catch { /* fall through */ }
  }
  // Fallback for HTTP / older browsers.
  try {
    const ta = document.createElement('textarea');
    ta.value = value;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    document.body.appendChild(ta);
    ta.select();
    const ok = document.execCommand('copy');
    document.body.removeChild(ta);
    return ok;
  } catch {
    return false;
  }
}

export function CopyButton({ value }: { value: string }) {
  const [status, setStatus] = useState<'idle' | 'copied' | 'error'>('idle');
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);

  async function onClick() {
    // Call clipboard write synchronously in the gesture - don't await anything first.
    const ok = await copyText(value);
    setStatus(ok ? 'copied' : 'error');
    if (timerRef.current) clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => setStatus('idle'), 2000);
  }

  return (
    <>
      <button onClick={onClick} disabled={status === 'copied'} className="px-2 py-1 border rounded">
        {status === 'copied' ? 'Copied!' : status === 'error' ? 'Press Ctrl+C' : 'Copy'}
      </button>
      <span aria-live="polite" className="sr-only">{status === 'copied' ? 'Copied to clipboard' : ''}</span>
    </>
  );
}

