// Production version: switch to @dnd-kit/core + @dnd-kit/sortable.
import { DndContext, DragEndEvent, KeyboardSensor, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import { SortableContext, useSortable, arrayMove, verticalListSortingStrategy, sortableKeyboardCoordinates } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { useState, useCallback } from 'react';

type Item = { id: string; text: string };

function SortableItem({ item }: { item: Item }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: item.id });
  return (
    <li
      ref={setNodeRef}
      style={{ transform: CSS.Transform.toString(transform), transition, opacity: isDragging ? 0.5 : 1 }}
      {...attributes}
      {...listeners}
      className="p-2 border"
    >
      {item.text}
    </li>
  );
}

export function DraggableList({ initial, onReorder }: { initial: Item[]; onReorder: (next: Item[]) => Promise<void> }) {
  const [items, setItems] = useState<Item[]>(initial);
  const [announcement, setAnnouncement] = useState('');
  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const onDragEnd = useCallback(async (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    const oldIndex = items.findIndex((i) => i.id === active.id);
    const newIndex = items.findIndex((i) => i.id === over.id);
    const next = arrayMove(items, oldIndex, newIndex);
    setItems(next);
    setAnnouncement(`Item moved to position ${newIndex + 1} of ${items.length}`);
    try {
      await onReorder(next);
    } catch {
      setItems(items); // rollback
      setAnnouncement('Reorder failed, undone');
    }
  }, [items, onReorder]);

  return (
    <>
      <DndContext sensors={sensors} onDragEnd={onDragEnd}>
        <SortableContext items={items.map((i) => i.id)} strategy={verticalListSortingStrategy}>
          <ul>{items.map((it) => <SortableItem key={it.id} item={it} />)}</ul>
        </SortableContext>
      </DndContext>
      <span aria-live="polite" className="sr-only">{announcement}</span>
    </>
  );
}

