export function GreetingWidget({ name }: { name?: string }) {
  // CHANGED: start with null; only render time-dependent content after mount
  const [now, setNow] = useState<Date | null>(null);

  useEffect(() => {
    // CHANGED: update on minute boundaries, pause when hidden
    setNow(new Date());
    let timeout: ReturnType<typeof setTimeout>;
    const tick = () => {
      if (document.hidden) return;
      setNow(new Date());
      const msUntilNextMinute = 60_000 - (Date.now() % 60_000);
      timeout = setTimeout(tick, msUntilNextMinute);
    };
    const msUntilNextMinute = 60_000 - (Date.now() % 60_000);
    timeout = setTimeout(tick, msUntilNextMinute);

    const onVisibility = () => { if (!document.hidden) tick(); };
    document.addEventListener('visibilitychange', onVisibility);
    return () => {
      clearTimeout(timeout);
      document.removeEventListener('visibilitychange', onVisibility);
    };
  }, []);

  return (
    <div className="text-2xl font-medium min-h-[2rem]">
      {/* CHANGED: only render time-dependent content client-side */}
      {now ? (
        <>{getGreeting(now)}{name ? `, ${name}` : ''}. It's {formatTime(now)}</>
      ) : name ? (
        <>Hi{name ? `, ${name}` : ''}.</>
      ) : null}
    </div>
  );
}

