import { useQuery } from '@tanstack/react-query';
import { useFilters } from '../store/filters';
import { useUser } from '../auth/useUser';

async function fetchActivity(userId: string, filters: Filters, signal: AbortSignal): Promise<{ items: Activity[] }> {
  // CHANGED: POST with body instead of JSON-in-URL
  const r = await fetch('/api/activity', {
    method: 'POST',
    body: JSON.stringify({ userId, filters }),
    headers: { 'Content-Type': 'application/json' },
    signal
  });
  if (!r.ok) throw new Error(`Activity fetch failed: ${r.status}`);
  return r.json();
}

export function ActivityWidget() {
  const filters = useFilters();
  const user = useUser();

  // CHANGED: React Query handles cancellation, race conditions, error states, and refetch coordination
  const { data, isPending, isError, error, isFetching } = useQuery({
    queryKey: ['activity', user.id, filters],
    queryFn: ({ signal }) => fetchActivity(user.id, filters, signal),
    placeholderData: (prev) => prev  // CHANGED: keep previous data during refetch to avoid skeleton flicker
  });

  if (isPending) return <Skeleton />;
  if (isError) return <ErrorState message={error.message} />;
  if (!data?.items.length) return <EmptyState message="No activity matches your filters" />;

  return (
    <div>
      {/* CHANGED: subtle indicator during refetch instead of skeleton */}
      {isFetching && <RefreshIndicator />}
      <ul>
        {data.items.map((a) => <li key={a.id}>{a.text}</li>)}
      </ul>
    </div>
  );
}

