// src/components/CommentList.tsx
import MarkdownIt from 'markdown-it';
import DOMPurify from 'dompurify';
import { useMemo } from 'react';

// CHANGED: factory to avoid shared mutable parser
function createMd() {
  const md = new MarkdownIt({ html: false, linkify: true });
  // CHANGED: linkify only http(s)
  md.linkify.set({ fuzzyProtocol: false });
  return md;
}

// CHANGED: DOMPurify hook adds target/rel ONLY for external http(s) links
DOMPurify.addHook('afterSanitizeAttributes', (node) => {
  if (node.nodeName === 'A' && node instanceof HTMLAnchorElement) {
    const href = node.getAttribute('href') ?? '';
    const isExternal = /^https?:\/\//i.test(href);
    if (isExternal) {
      node.setAttribute('target', '_blank');
      node.setAttribute('rel', 'noopener noreferrer');
    }
  }
});

const SAFE_TAGS = ['p', 'strong', 'em', 'a', 'code', 'pre', 'blockquote', 'br'];
const SAFE_ATTR = ['href', 'target', 'rel'];

function renderComment(text: string, md: MarkdownIt): string {
  const rawHtml = md.render(text);
  // CHANGED: no post-sanitize mutation; allowed tags/attrs explicit
  return DOMPurify.sanitize(rawHtml, { ALLOWED_TAGS: SAFE_TAGS, ALLOWED_ATTR: SAFE_ATTR });
}

// CHANGED: helper for safe author display
function safeAuthor(name: string): string {
  // Normalize unicode, strip bidi override chars
  const normalized = name.normalize('NFKC').replace(/[\u202A-\u202E\u2066-\u2069]/g, '');
  return normalized.length > 40 ? normalized.slice(0, 40) + '…' : normalized;
}

export function CommentList({ comments }: { comments: Comment[] }) {
  const md = useMemo(() => createMd(), []);
  return (
    <ul>
      {comments.map((c) => (
        <li key={c.id}>
          <strong>{safeAuthor(c.author)}</strong>
          <div dangerouslySetInnerHTML={{ __html: renderComment(c.text, md) }} />
        </li>
      ))}
    </ul>
  );
}
